// MARK: - Security Helpers

// KeychainHelper for secure storage of encryption keys
struct KeychainHelper {
    static let service = "com.mybankingapp.encryptionKey"

    static func save(key: String, data: Data) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]

        SecItemDelete(query as CFDictionary)

        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw FinancialError.keychainError(status)
        }
    }

    static func load(key: String) throws -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: kCFBooleanTrue!,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)

        if status == errSecItemNotFound {
            return nil
        } else if status != errSecSuccess {
            throw FinancialError.keychainError(status)
        }

        return item as? Data
    }
}

// DataEncryptor using CryptoKit for AES-GCM encryption
struct DataEncryptor {
    private static let keyIdentifier = "financialEncryptionKey"
    private var symmetricKey: SymmetricKey

    init() throws {
        if let keyData = try KeychainHelper.load(key: DataEncryptor.keyIdentifier) {
            self.symmetricKey = SymmetricKey(data: keyData)
        } else {
            let newKey = SymmetricKey(size: .bits256)
            try KeychainHelper.save(key: DataEncryptor.keyIdentifier, data: newKey.dataRepresentation)
            self.symmetricKey = newKey
        }
    }

    func encrypt<T: Encodable>(_ value: T) throws -> Data {
        let data = try JSONEncoder().encode(value)
        do {
            let sealedBox = try AES.GCM.seal(data, using: symmetricKey)
            guard let combined = sealedBox.combined else {
                throw FinancialError.encryptionFailed("Failed to combine sealed box components.")
            }
            return combined
        } catch {
            throw FinancialError.encryptionFailed(error.localizedDescription)
        }
    }

    func decrypt<T: Decodable>(_ data: Data, type: T.Type) throws -> T {
        do {
            let sealedBox = try AES.GCM.SealedBox(combined: data)
            let decryptedData = try AES.GCM.open(sealedBox, using: symmetricKey)
            return try JSONDecoder().decode(type, from: decryptedData)
        } catch {
            throw FinancialError.decryptionFailed(error.localizedDescription)
        }
    }
}

// Extension to convert SymmetricKey to Data
extension SymmetricKey {
    var dataRepresentation: Data {
        return self.withUnsafeBytes { Data($0) }
    }
}

