    // MARK: Transaction Processing

    func processTransaction(
        type: TransactionType,
        amount: Decimal,
        fromAccountId: UUID,
        toAccountId: UUID? = nil,
        description: String? = nil
    ) async throws -> Transaction {
        guard amount > 0 else {
            throw FinancialError.invalidAmount
        }

        guard let fromAccountIndex = accounts.firstIndex(where: { $0.id == fromAccountId }) else {
            throw FinancialError.accountNotFound
        }
        var fromAccount = accounts[fromAccountIndex]

        var newTransaction = Transaction(
            accountId: fromAccountId,
            recipientAccountId: toAccountId,
            type: type,
            amount: amount,
            description: description
        )

        // Pre-transaction balance check for withdrawals/transfers
        if type == .withdrawal || type == .transfer {
            guard fromAccount.balance >= amount else {
                newTransaction.status = .failed
                transactions.append(newTransaction)
                try? saveData()
                throw FinancialError.insufficientFunds
            }
        }
        
        var toAccount: Account?
        var toAccountIndex: Int?
        if type == .transfer {
            guard let recipientId = toAccountId else {
                newTransaction.status = .failed
                transactions.append(newTransaction)
                try? saveData()
                throw FinancialError.accountNotFound
            }
            toAccountIndex = accounts.firstIndex(where: { $0.id == recipientId })
            guard let index = toAccountIndex else {
                newTransaction.status = .failed
                transactions.append(newTransaction)
                try? saveData()
                throw FinancialError.accountNotFound
            }
            toAccount = accounts[index]
        }

        // --- Simulate secure submission to backend ---
        // Prepare a simplified, encrypted payload. In a real app, this payload would be much more detailed.
        let transactionPayload: [String: String] = [
            "type": type.rawValue,
            "amount": NSDecimalNumber(decimal: amount).stringValue,
            "fromAccount": fromAccountId.uuidString,
            "toAccount": toAccountId?.uuidString ?? "N/A",
            "description": description ?? ""
        ]
        let encryptedPayload = try dataEncryptor.encrypt(transactionPayload)
        
        let networkStatus = try await networkService.submitTransaction(encryptedPayload)

        newTransaction.status = networkStatus
        
