                }
            }
            accounts[fromAccountIndex] = fromAccount
        } else {
            throw FinancialError.transactionFailed("Backend processing failed for transaction: \(newTransaction.id)")
        }

        transactions.append(newTransaction)
        try saveData()

        return newTransaction
    }
